local LxBaseHandler = require("LApp.handler.LxBaseHandler")
---@class LxEquipHandler:LxBaseHandler
local LxEquipHandler = classX("LxEquipHandler", LxBaseHandler)

function LxEquipHandler:Initialize()
    LxBaseHandler.Initialize(self)
end

function LxEquipHandler:Dispose()
    LxBaseHandler.Dispose(self)
end

function LxEquipHandler:ClearHandler()
    LxBaseHandler.ClearHandler(self)
end

function LxEquipHandler:InitOk()
end

-- 完成登录后
function LxEquipHandler:LoginOk()
end

function LxEquipHandler:InitHandler()
    self:AddMsgHandler(LxProtoIds.EquipChangeResp, self.OnEquipChangeResp, self)
    self:AddMsgHandler(LxProtoIds.EquipWearResp, self.OnEquipWearResp, self)
    self:AddMsgHandler(LxProtoIds.EquipUnWearResp, self.OnEquipUnWearResp, self)
    self:AddMsgHandler(LxProtoIds.EquipStrengthResp, self.OnEquipStrengthResp, self)
    self:AddMsgHandler(LxProtoIds.EquipUpStarResp, self.OnEquipUpStarResp, self)
end


-- 装备变化
function LxEquipHandler:OnEquipChangeResp(pb)
    local LxEquipModule = ModuleCenter.Equip
    for k, v in ipairs(pb.addEquips) do
        LxEquipModule:SetBagData(v)
    end
    FireEvent(EventNames.EQUIP_BAG_CHANGE)
end

-- 穿戴装备 请求
function LxEquipHandler:EquipWearReq(heroId, equipId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.EquipWearReq)
    proto.heroId = heroId
    proto.equipId = equipId
    SendMessage(LxProtoIds.EquipWearReq, proto)
    local heroObj = ModuleCenter.Hero:GetHero(heroId)
    if equipId == 0 then
        self:SaveOldEquipAttr(nil, 3, heroId)
    else
        local equipObj = ModuleCenter.Equip:GetEquipInfo(equipId)
        local equipRef = GameTable.RoleEquipRef[equipObj.refId]
        self:SaveOldEquipAttr(heroObj.equips[equipRef.type], 0)
    end

end

-- 穿戴装备 返回
function LxEquipHandler:OnEquipWearResp(pb)
    local LxEquipModule = ModuleCenter.Equip
    if table.isempty(pb.dropEquips) or not pb.dropEquips[1] then
        ShowSysMsg(I18nText(11640))
        return
    end
    for k, v in ipairs(pb.dropEquips) do
        LxEquipModule:SetBagData(v)
    end
    FireEvent(EventNames.EQUIP_BAG_CHANGE)

    local equipId = tostring(pb.equipId)
    if equipId == "0" then
        ShowSysMsg(I18nText(11636))
        for i, v in ipairs(pb.dropEquips) do
            if tostring(v.heroId) ~= "0" then
                self:ShowUpInfo(equipId, 3, v.heroId)
                return
            end
        end
    else
        ShowSysMsg(I18nText(11637))
        self:ShowUpInfo(equipId, 0)
    end
end

-- 卸下装备 请求
function LxEquipHandler:EquipUnWearReq(heroId, part)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.EquipUnWearReq)
    proto.heroId = heroId
    proto.part = part
    SendMessage(LxProtoIds.EquipUnWearReq, proto)
end

-- 卸下装备 返回
function LxEquipHandler:OnEquipUnWearResp(pb)
    local LxEquipModule = ModuleCenter.Equip
    if not pb.dropEquips[1] then
        return
    end
    for k, v in ipairs(pb.dropEquips) do
        LxEquipModule:SetBagData(v)
    end
    FireEvent(EventNames.EQUIP_BAG_CHANGE)
    ShowSysMsg(I18nText(11638))
end

-- 强化(升级)装备 请求
--- @param items table 强化道具材料
--- @param equips table 装备材料
function LxEquipHandler:EquipStrengthReq(id, items, equips)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.EquipStrengthReq)
    proto.id = id
    local pitem = proto.items
    for i,v in ipairs(items) do
        local kv = pitem:add()
        kv.key = v.key
        kv.value = v.value
    end
    for i,v in ipairs(equips) do
        proto.equips:append(v)
    end
    SendMessage(LxProtoIds.EquipStrengthReq, proto)
    self:SaveOldEquipAttr(id, 1)
end

-- 强化(升级)装备 返回
function LxEquipHandler:OnEquipStrengthResp(pb)
    local LxEquipModule = ModuleCenter.Equip
    LxEquipModule:SetBagData(pb.equipObj)
    LxEquipModule:RemoveEquipList(pb.equips)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.EquipResolve, pb.thingsInfo)
    FireEvent(EventNames.EQUIP_BAG_CHANGE)
    ShowSysMsg(I18nText(11632))
    self:ShowUpInfo(pb.equipObj.id, 1)
end

-- 装备升星请求
--- @param id number 装备唯一id
--- @param equips table<number, number> 本体装备消耗
function LxEquipHandler:EquipUpStarReq(id, equips)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.EquipUpStarReq)
    proto.id = id
    for i,v in ipairs(equips) do
        proto.equips:append(v)
    end
    SendMessage(LxProtoIds.EquipUpStarReq, proto)
    self:SaveOldEquipAttr(id, 2)
end

-- 装备升星返回
function LxEquipHandler:OnEquipUpStarResp(pb)
    local LxEquipModule = ModuleCenter.Equip
    LxEquipModule:SetBagData(pb.equipObj)
    LxEquipModule:RemoveEquipList(pb.equips)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.EquipResolve, pb.thingsInfo)
    FireEvent(EventNames.EQUIP_BAG_CHANGE)
    ShowSysMsg(I18nText(11635))
    self:ShowUpInfo(pb.equipObj.id, 2)
end


-- 保存旧属性
--- @type number 0 穿戴装备 1 升级 2 升星 3 一键穿戴
function LxEquipHandler:SaveOldEquipAttr(id, type, heroId)
    self._oldPower = ModuleCenter.Role:GetRolePower()
    self._oldAttr = {}
    if (not id or id == "0") and type ~= 3 then
        return
    end
    local eqModule = ModuleCenter.Equip
    if type == 3 then
        local heroObj = ModuleCenter.Hero:GetHero(heroId)
        local attrMap = {}
        for i, v in ipairs(heroObj.equips) do
            if v ~= "0" then
                local equipObj = eqModule:GetEquipInfo(v)
                local stAttr = CtrlCenter.Equip:GetStrengthAttr(equipObj.refId, equipObj.level)
                local upDataAttr = CtrlCenter.Equip:GetStarAttr(equipObj.refId, equipObj.level, equipObj.star)
                for j, v2 in ipairs(stAttr) do
                    --if LxDataHelper.GetCombatAttributeIsShow(v2.refId) then
                        local value = v2.value + upDataAttr[j].value
                        if not attrMap[v2.refId] then
                            attrMap[v2.refId] = { refId = v2.refId, value = value, tar = v2.tar }
                        else
                            attrMap[v2.refId].value = attrMap[v2.refId].value + value
                        end
                    --end
                end
            end
        end
        for i, v in pairs(attrMap) do
            table.insert(self._oldAttr, v)
        end

    else
        local equipObj = eqModule:GetEquipInfo(id)
        local stAttr = CtrlCenter.Equip:GetStrengthAttr(equipObj.refId, equipObj.level)
        local upDataAttr = CtrlCenter.Equip:GetStarAttr(equipObj.refId, equipObj.level, equipObj.star)
        if type == 0 then
            for i, v in ipairs(stAttr) do
                local value = v.value + upDataAttr[i].value
                table.insert(self._oldAttr, { refId = v.refId, value = value, tar = v.tar })
            end
        elseif type == 1 then
            self._oldAttr = stAttr
        elseif type == 2 then
            self._oldAttr = upDataAttr
        end
    end


end

-- 显示属性提示
--- @type number 0 穿戴装备 1 升级 2 升星 3 一键穿戴
function LxEquipHandler:ShowUpInfo(id, type, heroId)
    if not self._oldPower then
        return
    end
    local newPower = ModuleCenter.Role:GetRolePower()
    if newPower <= self._oldPower then
        return
    end
    local newAttr = {}
    local eqModule = ModuleCenter.Equip
    if type == 3 then
        local heroObj = ModuleCenter.Hero:GetHero(heroId)
        if not heroObj then
            return
        end
        local attrMap = {}
        for i, v in ipairs(heroObj.equips) do
            if v ~= "0" then
                local equipObj = eqModule:GetEquipInfo(v)
                local stAttr = CtrlCenter.Equip:GetStrengthAttr(equipObj.refId, equipObj.level)
                local upDataAttr = CtrlCenter.Equip:GetStarAttr(equipObj.refId, equipObj.level, equipObj.star)
                for j, v2 in ipairs(stAttr) do
                    --if LxDataHelper.GetCombatAttributeIsShow(v2.refId) then
                        local value = v2.value + upDataAttr[j].value
                        if not attrMap[v2.refId] then
                            attrMap[v2.refId] = { refId = v2.refId, value = value, tar = v2.tar }
                        else
                            attrMap[v2.refId].value = attrMap[v2.refId].value + value
                        end
                    --end
                end
            end
        end
        for i, v in pairs(attrMap) do
            table.insert(newAttr, v)
        end
    else
        local equipObj = ModuleCenter.Equip:GetEquipInfo(id)
        local stAttr = CtrlCenter.Equip:GetStrengthAttr(equipObj.refId, equipObj.level)
        local upDataAttr = CtrlCenter.Equip:GetStarAttr(equipObj.refId, equipObj.level, equipObj.star)
        if type == 0 then
            for i, v in ipairs(stAttr) do
                local value = v.value + upDataAttr[i].value
                table.insert(newAttr, { refId = v.refId, value = value, tar = v.tar })
            end
        elseif type == 1 then
            newAttr = stAttr
        elseif type == 2 then
            newAttr = upDataAttr
        end
    end

    local data = {}
    data.oldPower = self._oldPower
    data.newPower = newPower
    data.old = self._oldAttr
    data.new = newAttr
    ShowPanel(UiNames.FloatUpInfo, data)
end




return LxEquipHandler
